  1→import { embed } from "ai";
  2→import { type RecordId, type Surreal } from "surrealdb";
  3→import { elapsedMs } from "../http/observability";
  4→import type { GraphEntityRecord } from "./types";
  5→import { log } from "../telemetry/logger";
  6→
  7→export async function persistEmbeddings(input: {
  8→  surreal: Surreal;
  9→  embeddingModel: any;
 10→  embeddingDimension: number;
 11→  assistantMessageRecord: RecordId<"message", string>;
 12→  assistantText: string;
 13→  entities: Array<{ record: GraphEntityRecord; text: string }>;
 14→}): Promise<void> {
 15→  const startedAt = performance.now();
 16→  log.info("embedding.persist.started", "Embedding persistence started", {
 17→    messageId: input.assistantMessageRecord.id as string,
 18→    entityCount: input.entities.length,
 19→  });
 20→
 21→  try {
 22→    const messageEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, input.assistantText);
 23→    if (messageEmbedding) {
 24→      await writeEmbedding({
 25→        surreal: input.surreal,
 26→        record: input.assistantMessageRecord,
 27→        embedding: messageEmbedding,
 28→        label: "assistant message",
 29→      });
 30→    }
 31→
 32→    let embeddedEntityCount = 0;
 33→    for (const entity of input.entities) {
 34→      const entityEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, entity.text);
 35→      if (!entityEmbedding) {
 36→        continue;
 37→      }
 38→
 39→      await writeEmbedding({
 40→        surreal: input.surreal,
 41→        record: entity.record as RecordId<string, string>,
 42→        embedding: entityEmbedding,
 43→        label: `${entity.record.table.name}:${entity.record.id as string}`,
 44→      });
 45→      embeddedEntityCount += 1;
 46→    }
 47→
 48→    log.info("embedding.persist.completed", "Embedding persistence completed", {
 49→      messageId: input.assistantMessageRecord.id as string,
 50→      entityCount: input.entities.length,
 51→      embeddedEntityCount,
 52→      durationMs: elapsedMs(startedAt),
 53→    });
 54→  } catch (error) {
 55→    log.error("embedding.persist.failed", "Embedding persistence failed", error, {
 56→      messageId: input.assistantMessageRecord.id as string,
 57→      entityCount: input.entities.length,
 58→      durationMs: elapsedMs(startedAt),
 59→    });
 60→    throw error;
 61→  }
 62→}
 63→
 64→export async function createEmbedding(
 65→  embeddingModel: any,
 66→  embeddingDimension: number,
 67→  value: string,
 68→): Promise<number[] | undefined> {
 69→  const normalized = value.trim();
 70→  if (normalized.length === 0) {
 71→    return undefined;
 72→  }
 73→
 74→  const result = await embed({
 75→    model: embeddingModel,
 76→    value: normalized,
 77→  });
 78→
 79→  if (result.embedding.length !== embeddingDimension) {
 80→    log.warn("embedding.dimension_mismatch", "Skipping embedding write due to vector dimension mismatch", {
 81→      actualDimension: result.embedding.length,
 82→      configuredDimension: embeddingDimension,
 83→    });
 84→    return undefined;
 85→  }
 86→
 87→  return result.embedding;
 88→}
 89→
 90→async function writeEmbedding(input: {
 91→  surreal: Surreal;
 92→  record: RecordId<string, string>;
 93→  embedding: number[];
 94→  label: string;
 95→}): Promise<void> {
 96→  const [updateResult] = await input.surreal
 97→    .query<[unknown]>(
 98→      "UPDATE $record MERGE $patch RETURN AFTER;",
 99→      {
100→        record: input.record,
101→        patch: { embedding: input.embedding },
102→      },
103→    )
104→    .collect<[unknown]>();
105→
106→  if (queryResultHasRecordId(updateResult)) {
107→    return;
108→  }
109→
110→  const verified = await verifyEmbeddingPresent(input.surreal, input.record, input.embedding.length);
111→  if (!verified) {
112→    throw new Error(`${input.label} embedding update verification failed`);
113→  }
114→
115→  log.warn(
116→    "embedding.persist.unexpected_update_output",
117→    "embedding update returned no row but verification succeeded",
118→    { record: input.label },
119→  );
120→}
121→
122→async function verifyEmbeddingPresent(
123→  surreal: Surreal,
124→  record: RecordId<string, string>,
125→  expectedDimension: number,
126→): Promise<boolean> {
127→  const [queryResult] = await surreal
128→    .query<[unknown]>("SELECT id, embedding FROM $record;", { record })
129→    .collect<[unknown]>();
130→  const row = extractRecordFromPayload(queryResult);
131→  if (!row || row.id === undefined) {
132→    return false;
133→  }
134→
135→  const vectorLength = readVectorLength(row.embedding);
136→  return vectorLength === expectedDimension;
137→}
138→
139→function queryResultHasRecordId(result: unknown): boolean {
140→  return flattenQueryResult(result).some((candidate) => {
141→    if (!candidate || typeof candidate !== "object" || !("id" in candidate)) {
142→      return false;
143→    }
144→    return (candidate as { id?: unknown }).id !== undefined;
145→  });
146→}
147→
148→function extractRecordFromPayload(value: unknown):
149→  | { id?: unknown; embedding?: unknown }
150→  | undefined {
151→  const candidates = flattenQueryResult(value).filter((entry) => entry && typeof entry === "object");
152→  const withId = candidates.find((entry) => "id" in (entry as Record<string, unknown>));
153→  if (withId) {
154→    return withId as { id?: unknown; embedding?: unknown };
155→  }
156→
157→  const first = candidates[0];
158→  return first ? (first as { id?: unknown; embedding?: unknown }) : undefined;
159→}
160→
161→function flattenQueryResult(value: unknown): unknown[] {
162→  if (!Array.isArray(value)) {
163→    return [value];
164→  }
165→
166→  const flattened: unknown[] = [];
167→  for (const entry of value) {
168→    if (Array.isArray(entry)) {
169→      flattened.push(...flattenQueryResult(entry));
170→      continue;
171→    }
172→    flattened.push(entry);
173→  }
174→
175→  return flattened;
176→}
177→
178→function readVectorLength(value: unknown): number | undefined {
179→  if (Array.isArray(value)) {
180→    return value.length;
181→  }
182→
183→  if (ArrayBuffer.isView(value)) {
184→    const arrayLike = value as { length?: number };
185→    if (typeof arrayLike.length === "number") {
186→      return arrayLike.length;
187→    }
188→  }
189→
190→  if (value && typeof value === "object" && Symbol.iterator in value) {
191→    const iterator = (value as { [Symbol.iterator]?: () => Iterator<unknown> })[Symbol.iterator];
192→    if (typeof iterator === "function") {
193→      return [...(value as Iterable<unknown>)].length;
194→    }
195→  }
196→
197→  return undefined;
198→}
