  1→import { RecordId } from "surrealdb";
  2→import { trace } from "@opentelemetry/api";
  3→import type { EntityKind, SearchEntityResponse } from "../../shared/contracts";
  4→import { HttpError } from "../http/errors";
  5→import { jsonError, jsonResponse } from "../http/response";
  6→import type { ServerDependencies } from "../runtime/types";
  7→import { resolveWorkspaceProjectRecord, resolveWorkspaceRecord } from "../workspace/workspace-scope";
  8→import { log } from "../telemetry/logger";
  9→
 10→type SearchEntityRow = {
 11→  id: RecordId<string, string>;
 12→  kind: EntityKind;
 13→  text: string;
 14→  score: number;
 15→};
 16→
 17→// BM25 full-text search queries per entity type.
 18→// Queries run from app layer because:
 19→// 1. search::score() / @N@ don't work inside DEFINE FUNCTION (https://github.com/surrealdb/surrealdb/issues/7013)
 20→// 2. @N@ doesn't work with SDK bound parameters — search term must be a string literal
 21→
 22→function escapeSearchQuery(query: string): string {
 23→  return query.replace(/\\/g, "\\\\").replace(/'/g, "\\'");
 24→}
 25→
 26→function buildWorkspaceSearchSQL(escapedQuery: string): string {
 27→  const q = `'${escapedQuery}'`;
 28→  return `
 29→SELECT id, "task" AS kind, title AS text, search::score(1) AS score
 30→FROM task WHERE title @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 31→
 32→SELECT id, "decision" AS kind, summary AS text, search::score(1) AS score
 33→FROM decision WHERE summary @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 34→
 35→SELECT id, "question" AS kind, text AS text, search::score(1) AS score
 36→FROM question WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 37→
 38→SELECT id, "observation" AS kind, text AS text, search::score(1) AS score
 39→FROM observation WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 40→
 41→SELECT id, "suggestion" AS kind, text AS text, search::score(1) AS score
 42→FROM suggestion WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 43→
 44→SELECT id, "feature" AS kind, name AS text, search::score(1) AS score
 45→FROM feature WHERE name @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 46→
 47→SELECT id, "project" AS kind, name AS text, search::score(1) AS score
 48→FROM project WHERE name @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 49→
 50→SELECT id, "person" AS kind, name AS text, search::score(1) AS score
 51→FROM person WHERE name @1@ ${q} ORDER BY score DESC LIMIT $limit;
 52→
 53→SELECT id, "message" AS kind, text AS text, search::score(1) AS score
 54→FROM message WHERE text @1@ ${q} AND conversation.workspace = $workspace ORDER BY score DESC LIMIT $limit;
 55→`;
 56→}
 57→
 58→function buildProjectSearchSQL(escapedQuery: string): string {
 59→  const q = `'${escapedQuery}'`;
 60→  return `
 61→LET $project_entity_ids = SELECT VALUE in FROM belongs_to WHERE out = $project;
 62→
 63→SELECT id, "task" AS kind, title AS text, search::score(1) AS score
 64→FROM task WHERE title @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 65→
 66→SELECT id, "decision" AS kind, summary AS text, search::score(1) AS score
 67→FROM decision WHERE summary @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 68→
 69→SELECT id, "question" AS kind, text AS text, search::score(1) AS score
 70→FROM question WHERE text @1@ ${q} AND workspace = $workspace AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 71→
 72→SELECT id, "observation" AS kind, text AS text, search::score(1) AS score
 73→FROM observation WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 74→
 75→SELECT id, "suggestion" AS kind, text AS text, search::score(1) AS score
 76→FROM suggestion WHERE text @1@ ${q} AND workspace = $workspace ORDER BY score DESC LIMIT $limit;
 77→
 78→SELECT id, "feature" AS kind, name AS text, search::score(1) AS score
 79→FROM feature WHERE name @1@ ${q} AND id IN $project_entity_ids ORDER BY score DESC LIMIT $limit;
 80→
 81→SELECT id, "message" AS kind, text AS text, search::score(1) AS score
 82→FROM message WHERE text @1@ ${q} AND conversation.workspace = $workspace ORDER BY score DESC LIMIT $limit;
 83→`;
 84→}
 85→
 86→export function createEntitySearchHandler(deps: ServerDependencies): (url: URL) => Promise<Response> {
 87→  return (url: URL) => handleEntitySearch(deps, url);
 88→}
 89→
 90→async function handleEntitySearch(deps: ServerDependencies, url: URL): Promise<Response> {
 91→  const span = trace.getActiveSpan();
 92→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 93→  if (!workspaceId) {
 94→    return jsonError("workspaceId is required", 400);
 95→  }
 96→
 97→  const projectId = url.searchParams.get("projectId")?.trim();
 98→
 99→  const query = url.searchParams.get("q")?.trim();
100→  if (!query) {
101→    return jsonError("q is required", 400);
102→  }
103→
104→  const rawLimit = url.searchParams.get("limit");
105→  const parsedLimit = Number(rawLimit ?? "10");
106→  if (!Number.isFinite(parsedLimit) || parsedLimit < 1) {
107→    return jsonError("limit must be a positive number", 400);
108→  }
109→
110→  const limit = Math.min(Math.floor(parsedLimit), 100);
111→
112→  // Wide event: enrich span with search context
113→  span?.setAttribute("workspace.id", workspaceId);
114→  span?.setAttribute("search.query_length", query.length);
115→  span?.setAttribute("search.limit", limit);
116→  if (projectId) span?.setAttribute("search.project_id", projectId);
117→
118→  let workspaceRecord: RecordId<"workspace", string>;
119→  let projectRecord: RecordId<"project", string> | undefined;
120→
121→  try {
122→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
123→    if (projectId) {
124→      projectRecord = await resolveWorkspaceProjectRecord(deps.surreal, workspaceRecord, projectId);
125→    }
126→  } catch (error) {
127→    if (error instanceof HttpError) {
128→      throw error; // withTracing handles HttpError → proper status code + span attributes
129→    }
130→    log.error("entity.search.scope_validation.failed", "Entity search scope validation failed", error, {
131→      workspaceId,
132→      projectId,
133→    });
134→    const errorText = error instanceof Error ? error.message : "failed to validate scope";
135→    return jsonError(errorText, 500);
136→  }
137→
138→  const escaped = escapeSearchQuery(query);
139→  const sql = projectRecord
140→    ? buildProjectSearchSQL(escaped)
141→    : buildWorkspaceSearchSQL(escaped);
142→
143→  const bindings = {
144→    limit,
145→    workspace: workspaceRecord,
146→    ...(projectRecord ? { project: projectRecord } : {}),
147→  };
148→
149→  const results = await deps.surreal.query(sql, bindings);
150→
151→  const allRows = (results as unknown as SearchEntityRow[][])
152→    .filter(Array.isArray)
153→    .flat()
154→    .sort((a, b) => b.score - a.score)
155→    .slice(0, limit);
156→
157→  const responseRows = allRows.map((row) => ({
158→    id: row.id.id as string,
159→    kind: row.kind,
160→    text: row.text,
161→    confidence: row.score,
162→    sourceId: "",
163→    sourceKind: "message",
164→  } satisfies SearchEntityResponse));
165→
166→  span?.setAttribute("search.result_count", responseRows.length);
167→  span?.setAttribute("search.scope", projectRecord ? "project" : "workspace");
168→
169→  return jsonResponse(responseRows, 200);
170→}
