 913→export async function searchEntitiesByEmbedding(input: {
 914→  surreal: Surreal;
 915→  workspaceRecord: RecordId<"workspace", string>;
 916→  queryEmbedding: number[];
 917→  kinds?: SearchEntityKind[];
 918→  projectRecord?: RecordId<"project", string>;
 919→  limit: number;
 920→}): Promise<RankedEntity[]> {
 921→  const candidates = await listScopedEntityCandidates({
 922→    surreal: input.surreal,
 923→    workspaceRecord: input.workspaceRecord,
 924→    kinds: input.kinds,
 925→    projectRecord: input.projectRecord,
 926→    candidateLimit: Math.max(input.limit * 20, 120),
 927→  });
 928→
 929→  const rows = candidates
 930→    .map((candidate) => ({
 931→      candidate,
 932→      score: candidate.embedding ? cosineSimilarity(input.queryEmbedding, candidate.embedding) : -1,
 933→    }))
 934→    .filter((row) => row.score > 0)
 935→    .sort((a, b) => b.score - a.score)
 936→    .slice(0, input.limit);
 937→
 938→  return rows.map((row) => ({
 939→    id: toRecordIdString(row.candidate.id),
 940→    kind: row.candidate.kind,
 941→    name: row.candidate.name,
 942→    score: row.score,
 943→    ...(row.candidate.status ? { status: row.candidate.status } : {}),
 944→  }));
 945→}
 946→
 947→type UnifiedEdgeRow = {
 948→  id: RecordId<string, string>;
 949→  in: RecordId<string, string>;
 950→  out: RecordId<string, string>;
 951→  kind?: string; // only entity_relation has this field
 952→  confidence?: number; // only entity_relation has this field
 953→};
 954→
 955→export async function listEntityNeighbors(input: {
 956→  surreal: Surreal;
 957→  workspaceRecord: RecordId<"workspace", string>;
 958→  entityRecord: GraphEntityRecord;
 959→  limit: number;
 960→}): Promise<EntityNeighbor[]> {
 961→  const [rows] = await input.surreal
 962→    .query<[UnifiedEdgeRow[]]>(
 963→      "RETURN fn::entity_edges($entity, $limit);",
 964→      { entity: input.entityRecord, limit: input.limit },
 965→    )
 966→    .collect<[UnifiedEdgeRow[]]>();
 967→
 968→  const neighbors: EntityNeighbor[] = [];
 969→  const seen = new Set<string>();
 970→
 971→  for (const row of rows) {
 972→    const edgeTable = row.id.table.name;
 973→    const relationKind = row.kind ?? edgeTable;
 974→    const direction = toRecordIdString(row.in) === toRecordIdString(input.entityRecord) ? "outgoing" : "incoming";
 975→    const neighborRecord = direction === "outgoing" ? row.out : row.in;
 976→    const key = `${relationKind}:${toRecordIdString(neighborRecord)}`;
 977→    if (seen.has(key)) continue;
 978→
 979→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, neighborRecord as GraphEntityRecord);
 980→    if (!scoped) continue;
 981→
 982→    const name = await readEntityName(input.surreal, neighborRecord as GraphEntityRecord);
 983→    if (!name) continue;
 984→
 985→    seen.add(key);
 986→    neighbors.push({
