  1→/**
  2→ * Pure Alignment Evaluator
  3→ *
  4→ * Computes cosine similarity between intent and objective embeddings,
  5→ * then classifies the alignment result.
  6→ *
  7→ * PURE MODULE: No IO imports, no side effects. Receives data, returns data.
  8→ */
  9→
 10→// ---------------------------------------------------------------------------
 11→// Types
 12→// ---------------------------------------------------------------------------
 13→
 14→export type AlignmentClassification = "matched" | "ambiguous" | "none";
 15→
 16→export type AlignmentCandidate = {
 17→  objectiveId: string;
 18→  title: string;
 19→  score: number;
 20→};
 21→
 22→export type AlignmentResult = {
 23→  classification: AlignmentClassification;
 24→  objectiveId?: string;
 25→  title?: string;
 26→  score: number;
 27→};
 28→
 29→// ---------------------------------------------------------------------------
 30→// Cosine Similarity
 31→// ---------------------------------------------------------------------------
 32→
 33→/**
 34→ * Computes cosine similarity between two vectors.
 35→ * Returns 0 if either vector has zero magnitude.
 36→ */
 37→export function computeCosineSimilarity(
 38→  vectorA: number[],
 39→  vectorB: number[],
 40→): number {
 41→  if (vectorA.length !== vectorB.length) {
 42→    throw new Error(
 43→      `Vector length mismatch: vectorA has ${vectorA.length} dimensions, vectorB has ${vectorB.length}`,
 44→    );
 45→  }
 46→
 47→  let dotProduct = 0;
 48→  let magnitudeA = 0;
 49→  let magnitudeB = 0;
 50→
 51→  for (let i = 0; i < vectorA.length; i++) {
 52→    dotProduct += vectorA[i] * vectorB[i];
 53→    magnitudeA += vectorA[i] * vectorA[i];
 54→    magnitudeB += vectorB[i] * vectorB[i];
 55→  }
 56→
 57→  const magnitude = Math.sqrt(magnitudeA) * Math.sqrt(magnitudeB);
 58→  if (magnitude === 0) return 0;
 59→
 60→  return dotProduct / magnitude;
 61→}
 62→
 63→// ---------------------------------------------------------------------------
 64→// Classification
 65→// ---------------------------------------------------------------------------
 66→
 67→const MATCHED_THRESHOLD = 0.7;
 68→const AMBIGUOUS_THRESHOLD = 0.5;
 69→
 70→/**
 71→ * Classifies a cosine similarity score into an alignment category.
 72→ *
 73→ * - matched:   score >= 0.7 (strong semantic alignment)
 74→ * - ambiguous: score >= 0.5 (weak alignment, human review suggested)
 75→ * - none:      score < 0.5  (no meaningful alignment)
 76→ */
 77→export function classifyAlignment(score: number): AlignmentClassification {
 78→  if (score >= MATCHED_THRESHOLD) return "matched";
 79→  if (score >= AMBIGUOUS_THRESHOLD) return "ambiguous";
 80→  return "none";
 81→}
 82→
 83→// ---------------------------------------------------------------------------
 84→// Best Match Selection
 85→// ---------------------------------------------------------------------------
 86→
 87→/**
 88→ * Selects the best alignment from a list of scored candidates.
 89→ *
 90→ * Returns the highest-scoring candidate with its classification.
 91→ * If no candidates exist or the best score is below the ambiguous threshold,
 92→ * the objectiveId is omitted from the result.
 93→ */
 94→export function selectBestAlignment(
 95→  candidates: AlignmentCandidate[],
 96→): AlignmentResult {
 97→  if (candidates.length === 0) {
 98→    return { classification: "none", score: 0 };
 99→  }
100→
101→  const sorted = [...candidates].sort((a, b) => b.score - a.score);
102→  const best = sorted[0];
103→  const classification = classifyAlignment(best.score);
104→
105→  if (classification === "none") {
106→    return { classification, score: best.score };
107→  }
108→
109→  return {
110→    classification,
111→    objectiveId: best.objectiveId,
112→    title: best.title,
113→    score: best.score,
114→  };
115→}
